// Access the AI Agent's output
const sheetUrl="https://docs.google.com/spreadsheets/d/1Hy1FrHDAVmUv3GNkKpF-PrarKTJqfzgl7DkM6hD_3hQ/edit?gid=0#gid=0";
const aiOutput =$input.first().json.output ;
const data = typeof aiOutput === 'string' ? JSON.parse(aiOutput) : aiOutput;

// Logic to determine if the run failed:
// 1. Status is not "success"
// 2. total_failing is greater than 0
// 3. The 'err' field is not null
const hasIssues = data.status !== "success" || 
                  (data.data && data.data.total_failing > 0) || 
                  data.err !== null;

let message = "";

if (!hasIssues) {
    message = `✅ **All tests passed successfully!**\n\n` +
              `The QA report for ${data.data.run_date} is complete.\n` +
              `Total tests executed: ${data.data.total_tests}.\n` +
              `Everything is running smoothly! 🚀
              You can check the detailed reportt here\n
              ${sheetUrl}
              `;
} else {
    const errorReason = data.err || "Tests did not meet the success criteria or failures were detected.";
    message = `⚠️ **Attention required: Test suite issues detected.**\n\n` +
              `Date: ${data.data.run_date}\n` +
              `Tests failed: ${data.data.total_failing || "N/A"}\n` +
              `Reason: ${errorReason}\n\n` +
              `Please review the generated report for more details.`;
}

// Return the two required variables
return {
    json: {
        formatted_message: message,
        isFailed: hasIssues
    }
};
